// Récupère les réservations et construit le résumé + les conseils tarifaires.
const resp = $input.first().json;
const items = (resp.items || []).filter(b => (b.status || '').toLowerCase() === 'booked');

const today = new Date();
const ymNow = today.getFullYear() + '-' + String(today.getMonth()+1).padStart(2,'0');

function daysInMonth(ym){ const [y,m]=ym.split('-').map(Number); return new Date(y,m,0).getDate(); }
function addMonths(ym,n){ let [y,m]=ym.split('-').map(Number); m+=n; y+=Math.floor((m-1)/12); m=((m-1)%12+12)%12+1; return y+'-'+String(m).padStart(2,'0'); }

// Occupation par propriété et par mois (nuits réparties)
const byProp = {};
for (const b of items){
  const pid = b.property_id ?? '?';
  const name = b.property_name || ('Propriété ' + pid);
  const start = new Date(b.arrival || b.date_arrival);
  const end = new Date(b.departure || b.date_departure);
  if (isNaN(start) || isNaN(end)) continue;
  byProp[pid] = byProp[pid] || { name, months:{}, arrivals:[] };
  if (start >= today && (start - today)/86400000 <= 14){
    byProp[pid].arrivals.push({ arrival:b.arrival, nights:Math.round((end-start)/86400000), total:b.total });
  }
  for (let d=new Date(start); d<end; d.setDate(d.getDate()+1)){
    const ym = d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0');
    byProp[pid].months[ym] = (byProp[pid].months[ym]||0)+1;
  }
}

// Conseils tarifaires sur les 3 prochains mois
const SEUIL = 35;           // sous ce taux (%) → suggestion de baisse
const months3 = [ymNow, addMonths(ymNow,1), addMonths(ymNow,2)];
const FR = ['janvier','février','mars','avril','mai','juin','juillet','août','septembre','octobre','novembre','décembre'];
function moisFr(ym){ const [y,m]=ym.split('-'); return FR[+m-1]+' '+y; }

let blocks = '';
for (const p of Object.values(byProp)){
  let arr = p.arrivals.sort((a,b)=> new Date(a.arrival)-new Date(b.arrival))
    .map(a=>`<li>${new Date(a.arrival).toLocaleDateString('fr-FR')} — ${a.nights} nuit(s)${a.total?` · ${a.total} €`:''}</li>`).join('') || '<li>aucune arrivée sous 14 jours</li>';
  let advice = '';
  for (const ym of months3){
    const nights = p.months[ym]||0;
    const occ = Math.round(nights/daysInMonth(ym)*100);
    if (occ < SEUIL){
      const fort = [6,7,8].includes(+ym.split('-')[1]); // juin-août
      advice += `<li><b>${moisFr(ym)}</b> : ${occ}% de remplissage — ${fort?'⚠️ mois de haute saison sous-rempli, baisse tarifaire urgente conseillée':'envisager une baisse de prix ou une promo dernière minute'}</li>`;
    }
  }
  if(!advice) advice = '<li>prochains mois bien remplis, rien à signaler ✅</li>';
  blocks += `<h3 style="color:#1F3B5C;margin:18px 0 6px">${p.name}</h3>`+
    `<p style="margin:2px 0;color:#555"><b>Arrivées à venir :</b></p><ul>${arr}</ul>`+
    `<p style="margin:8px 0 2px;color:#555"><b>Conseils tarifaires :</b></p><ul>${advice}</ul>`;
}

const html = `<div style="font-family:Arial,sans-serif;max-width:640px">`+
  `<h2 style="color:#1F3B5C">Point quotidien — ${today.toLocaleDateString('fr-FR')}</h2>`+
  `<p style="color:#555">Total réservations à venir : <b>${items.length}</b></p>`+
  blocks +
  `<p style="color:#999;font-size:12px;margin-top:20px">Généré automatiquement depuis l'API Lodgify.</p></div>`;

return [{ json: { html, subject: `Réservations & tarifs — ${today.toLocaleDateString('fr-FR')}` } }];
